final:
module top_module(
    input clk,
    input rst,
    output reg [2:0] count
);reg [2:0] err_next;

always @ (posedge clk) begin
    if (rst) begin
        count <= 3'b0;
    end
    else begin
        count <= err_next;
    end
end

always @ (*) begin
    case (count)
        3'b000: err_next = 3'b001;
        3'b001: err_next = 3'b010;
        3'b010: err_next = 3'b011;
        3'b011: err_next = 3'b100;
        3'b100: err_next = 3'b101;
        3'b101: err_next = 3'b110;
        3'b110: err_next = 3'b111;
        3'b111: err_next = 3'b000;
        default: err_next = 3'b0;
    endcase
end

endmodule
